269	type federationHeartbeatRequest struct {
270		NodeID string `json:"node_id"`
271	}
272	
273	func (s *Server) handleFederationHeartbeat(w http.ResponseWriter, r *http.Request) {
274		var req federationHeartbeatRequest
275		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
276			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
277			return
278		}
279		req.NodeID = strings.TrimSpace(req.NodeID)
280		if req.NodeID == "" {
281			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
282			return
283		}
284	
285		s.hub.mu.Lock()
286		defer s.hub.mu.Unlock()
287	
288		rec := s.hub.registry.FindSpoke(req.NodeID)
289		if rec == nil {
290			writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not registered"})
291			return
292		}
293		now := s.hub.now().UTC()
294		rec.LastHeartbeat = now
295		// Heartbeat clears registered-on-first-seen and offline; preserves
296		// degraded (set by the version handshake at registration time).
297		if rec.Status == federation.StatusRegistered || rec.Status == federation.StatusOffline || rec.Status == federation.StatusStale {
298			rec.Status = federation.StatusActive
299		}
300		s.persistFederationLocked()
301	
302		writeJSON(w, http.StatusOK, map[string]any{
303			"node_id":        rec.NodeID,
304			"status":         rec.Status,
305			"last_heartbeat": rec.LastHeartbeat,
306		})
307	}
