309	func (s *Server) handleFederationListSpokes(w http.ResponseWriter, _ *http.Request) {
310		s.hub.mu.Lock()
311		defer s.hub.mu.Unlock()
312		out := make([]federation.SpokeRecord, 0, len(s.hub.registry.Spokes))
313		out = append(out, s.hub.registry.Spokes...)
314		writeJSON(w, http.StatusOK, map[string]any{
315			"schema_version": s.hub.registry.SchemaVersion,
316			"spokes":         out,
317		})
318	}
319	
320	func (s *Server) handleFederationDeregister(w http.ResponseWriter, r *http.Request) {
321		id := strings.TrimSpace(r.PathValue("id"))
322		if id == "" {
323			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id required"})
324			return
325		}
326		s.hub.mu.Lock()
327		defer s.hub.mu.Unlock()
328		if !s.hub.registry.RemoveSpoke(id) {
329			writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not found"})
330			return
331		}
332		s.persistFederationLocked()
333		writeJSON(w, http.StatusOK, map[string]string{"node_id": id, "status": "deregistered"})
334	}
335	
336	// persistFederationLocked saves the registry to disk if a state path is set.
337	// Caller must hold s.hub.mu.
338	func (s *Server) persistFederationLocked() {
339		if s.hub.statePath == "" {
340			return
341		}
342		if err := federation.SaveStateTo(s.hub.statePath, s.hub.registry); err != nil {
343			s.hub.warnLog("federation: persist state: %v", err)
344		}
345	}
